const ctx = $("Load Owner Context").first().json || {};
const incoming = $("Incoming Payload").first().json || {};
const pendingOrders = $("Load Pending Orders").all()
  .map(function (item) { return item.json || {}; })
  .filter(function (order) { return order.order_number; });

function safeParse(value, fallback) {
  if (value === null || value === undefined || value === "") return fallback;
  if (typeof value === "string") {
    try {
      const parsed = JSON.parse(value);
      return parsed === null || parsed === undefined ? fallback : parsed;
    } catch (error) {
      return fallback;
    }
  }
  return value;
}

function asArray(value) {
  const parsed = safeParse(value, []);
  return Array.isArray(parsed) ? parsed : [];
}

function asObject(value) {
  const parsed = safeParse(value, {});
  return parsed && typeof parsed === "object" && !Array.isArray(parsed) ? parsed : {};
}

function getMemory(memories, key) {
  const row = memories.find(function (item) {
    return item && item.key === key;
  });
  return row ? String(row.value || "") : "";
}

function formatMoney(value) {
  const amount = Number(value || 0);
  return Number.isFinite(amount) ? amount.toLocaleString("en-NG") : String(value || "0");
}

function formatLocalNow() {
  try {
    return new Intl.DateTimeFormat("en-NG", {
      timeZone: "Africa/Lagos",
      weekday: "short",
      month: "short",
      day: "numeric",
      year: "numeric",
      hour: "2-digit",
      minute: "2-digit"
    }).format(new Date());
  } catch (error) {
    return new Date().toISOString();
  }
}

function formatWhen(value) {
  if (!value) return "";
  try {
    return new Date(value).toLocaleString("en-NG", {
      timeZone: "Africa/Lagos",
      weekday: "short",
      month: "short",
      day: "numeric",
      hour: "2-digit",
      minute: "2-digit"
    });
  } catch (error) {
    return "";
  }
}

function formatItems(items) {
  const parsed = Array.isArray(items) ? items : safeParse(items, []);
  if (!Array.isArray(parsed) || !parsed.length) return "";
  return parsed
    .map(function (item) {
      const qty = item.quantity || 1;
      const name = item.name || "item";
      return String(qty) + "x " + String(name);
    })
    .join(", ");
}

function formatAddress(address) {
  const parsed = asObject(address);

  const contactName =
    parsed.recipient_name ||
    parsed.contact_name ||
    parsed.name ||
    "";

  const contactPhone =
    parsed.recipient_phone ||
    parsed.contact_phone ||
    parsed.phone ||
    "";

  const city = parsed.city || "";
  const state = parsed.state || "";
  const country = parsed.country || "";
  const street =
    parsed.location_text ||
    parsed.street ||
    parsed.address ||
    "";

  const locationParts = [street, city, state, country].filter(Boolean);
  const location = parsed.location_type === "business_location"
    ? "business location"
    : locationParts.join(", ");

  const locationShort = [city, state].filter(Boolean).join(", ") || street || "";

  return {
    contactName: contactName,
    contactPhone: contactPhone,
    contact: [contactName, contactPhone].filter(Boolean).join(" / "),
    location: location,
    locationShort: locationShort
  };
}

function buildOrderDescriptor(order) {
  const deliveryType = String(order.delivery_type || "").toLowerCase();
  const items = formatItems(order.items);
  const address = formatAddress(order.delivery_address);
  const whenText = formatWhen(order.scheduled_for);

  const parts = [];
  const lead =
    items ||
    (deliveryType === "appointment" ? "booking" : "order");

  parts.push(lead);

  if (address.contactName) {
    parts.push("for " + address.contactName);
  }

  if (deliveryType === "delivery" && address.locationShort) {
    parts.push("to " + address.locationShort);
  } else if (deliveryType === "pickup") {
    parts.push("pickup");
  }

  if (whenText) {
    parts.push("scheduled " + whenText);
  }

  if (order.total_amount !== null && order.total_amount !== undefined && order.total_amount !== "") {
    parts.push("₦" + formatMoney(order.total_amount));
  }

  return parts.join(" | ");
}

function formatOrderLine(order, typicalDuration) {
  const descriptor = buildOrderDescriptor(order);
  const address = formatAddress(order.delivery_address);
  const whenText = formatWhen(order.scheduled_for);

  let line = "- " + descriptor + " (" + String(order.order_number) + ")";
  line += " | status: " + String(order.status || "n/a");
  line += " | payment: " + String(order.payment_status || "n/a");
  line += " | type: " + String(order.delivery_type || "n/a");

  if (whenText && typicalDuration && String(order.delivery_type || "").toLowerCase() === "appointment") {
    line += " | duration: " + typicalDuration;
  }

  if (address.contactPhone) {
    line += " | phone: " + address.contactPhone;
  }

  if (address.location && String(order.delivery_type || "").toLowerCase() !== "delivery") {
    line += " | location: " + address.location;
  }

  if (order.customer_notes) {
    line += " | specs: " + String(order.customer_notes);
  }

  if (order.customer_chat_id) {
    line += " | customer_chat_id: " + String(order.customer_chat_id);
  }

  return line;
}

function formatCandidateLine(order) {
  return "- " + buildOrderDescriptor(order) + " (" + String(order.order_number) + ")";
}

function section(title, body, sep) {
  if (!body) return "";
  return sep + "\n" + title + "\n" + sep + "\n" + body;
}

const memories = asArray(ctx.agent_memories);
const toneProfile = asObject(ctx.tone_profile);
const operatingHours = asObject(ctx.operating_hours);
const operatingDays = asArray(ctx.operating_days);

const agentRulesSource =
  ctx.agent_rules && ctx.agent_rules.rules !== undefined
    ? ctx.agent_rules.rules
    : (ctx.agent_rules || []);

const agentRules = Array.isArray(agentRulesSource) ? agentRulesSource : asArray(agentRulesSource);

const agentName = ctx.agent_name || "MyGuy";
const businessName = ctx.business_name || "your business";
const ownerName =
  ctx.preferred_name ||
  ctx.full_name ||
  incoming.display_name ||
  incoming.username ||
  "Boss";

const businessType = ctx.business_type || "";
const businessDesc = ctx.business_description || "";
const businessLocation = ctx.business_location || "";
const catalogueSummary = ctx.catalogue_summary || "No catalogue yet.";
const toneSummary = toneProfile.tone_summary || "friendly and professional";
const replyLanguage = String(ctx.reply_language || ctx.last_language_style || "en").toLowerCase();

const businessMode = ctx.business_mode || getMemory(memories, "business_mode") || "product_only";
const isServiceBusiness = businessMode === "service_only";
const isProductBusiness = businessMode === "product_only";
const isHybrid = businessMode === "hybrid_product_led" || businessMode === "hybrid_service_led";
const hasServiceComponent = isServiceBusiness || isHybrid;
const hasProductComponent = isProductBusiness || isHybrid;

const typicalDuration = getMemory(memories, "typical_session_duration");
const depositPolicy = getMemory(memories, "deposit_policy");
const cancellationPolicy = getMemory(memories, "cancellation_policy");

let hoursText = "";
if (operatingDays.length) {
  hoursText = "Operating days: " + operatingDays.join(", ");
  if (operatingHours.open && operatingHours.close) {
    hoursText += " (" + operatingHours.open + " - " + operatingHours.close + ")";
  }
}

const source = incoming.source || "telegram";
const msgType = incoming.message_type || "text";
const imageUrl = incoming.image_id || "";
const sep = "══════════════════════════════════════════════════";

const activeOrdersText = pendingOrders.length
  ? pendingOrders.map(function (order) {
      return formatOrderLine(order, typicalDuration);
    }).join("\n")
  : "No active orders or bookings right now.";

const orderConfirmCandidates = pendingOrders.filter(function (order) {
  const status = String(order.status || "").toLowerCase();
  return ["enquiry", "placed", "pending"].includes(status);
});

const paymentConfirmCandidates = pendingOrders.filter(function (order) {
  return String(order.payment_status || "").toLowerCase() === "proof_submitted";
});

const confirmCandidatesText = orderConfirmCandidates.length
  ? orderConfirmCandidates.map(formatCandidateLine).join("\n")
  : "None.";

const paymentCandidatesText = paymentConfirmCandidates.length
  ? paymentConfirmCandidates.map(formatCandidateLine).join("\n")
  : "None.";

const memoryText = memories.length
  ? memories.map(function (item) {
      return "- " + item.key + ": " + item.value;
    }).join("\n")
  : "None.";

const rulesText = agentRules.length
  ? agentRules.map(function (rule) {
      return "- " + rule;
    }).join("\n")
  : "None.";

const ownerContext = [
  "Owner: " + ownerName,
  "Business: " + businessName,
  businessType ? "Type: " + businessType : "",
  businessDesc ? "Description: " + businessDesc : "",
  businessLocation ? "Location: " + businessLocation : "",
  hoursText,
  "Default reply language: " + (replyLanguage === "pidgin" ? "Pidgin" : "English"),
  "Current Lagos time: " + formatLocalNow(),
  "Source: " + source,
  "Message type: " + msgType,
  imageUrl ? "Source image URL: " + imageUrl : "",
  "",
  "Catalogue / offer: " + catalogueSummary,
  "",
  "Business memory:",
  memoryText,
  "",
  "Business rules:",
  rulesText
].filter(Boolean).join("\n");

const languageRules = [
  "Tone: " + toneSummary,
  "Use either full English or full Pidgin based on the owner message. Never mix both in one reply.",
  "Keep replies short, usually 1 to 3 sentences.",
  "Lead with the answer, result, or question.",
  "Do not narrate what you are about to do.",
  "Never say you are an AI, bot, or assistant.",
  "Use short clarification questions when more than one record fits."
].join("\n");

const responseHygiene = [
  "One reply should contain one clean answer or one clean question.",
  "Never repeat the same sentence, request, or reassurance in the same message.",
  "If only one field is missing, ask only for that field.",
  "If several dispatch fields are missing, ask for all of them once in one concise message.",
  "Do not dump the full active-orders list unless the owner asked for a list."
].join("\n");

const clarificationStyle = [
  "When clarifying between orders, use natural descriptors first and order number second.",
  "Good style: Do you mean the 2x kaftan delivery to Yaba for Ada (MSQ-123456) or the pickup order for Tunde (MSQ-654321)?",
  "Bad style: Do you mean MSQ-123456 or MSQ-654321?",
  "Do not ask with order numbers alone if items, recipient, location, amount, or timing can distinguish the candidates."
].join("\n");

const routingRules = [
  "Use List Orders for general order lists or the latest active items.",
  "Use Get Order Details before mutating an order when the target is not already clear.",
  "Use Confirm Order only for confirming a specific order or booking.",
  "Use Update Order Status only for status-only changes.",
  "Use Confirm Payment only after the target order is resolved.",
  "Use Terminal Africa tools only for actual courier delivery, not simple status changes.",
  "Use Context Resolver only for saved product image lookup or existing dispatch lookup.",
  "Use Save Product Image only when the current message includes an image and the product name is known.",
  "Use Get Balance & Recharge Info for MySquad balance, pricing, and top-up questions.",
  "Use Get Credit Usage History for spend breakdown questions.",
  "Use Call Speedy Tool for personal banking actions like transfers, bank balance, airtime, and bills.",
  "Use Call Google Tools for Gmail and Calendar.",
  "Use Web Search Tool for current facts, live news, rates, prices, rankings, and anything that may have changed recently."
].join("\n");

const orderRules = [
  "You manage " + (
    hasServiceComponent && !hasProductComponent
      ? "bookings"
      : hasProductComponent && !hasServiceComponent
        ? "orders"
        : "orders and bookings"
  ) + " for " + businessName + ".",
  "When showing order details, surface items or service, amount, delivery_type, schedule if any, address or contact if any, specs, and payment status.",
  "Resolve an order from table_28 language using order number, item name, recipient name, city, state, street, amount, delivery type, schedule, or recency.",
  "If exactly one candidate fits, proceed.",
  "If more than one candidate fits, ask one short clarification and stop. Do not mutate yet.",
  "If no candidate fits, ask for the order number or a clearer reference.",
  "For payment confirmation, prefer the ORDERS AWAITING PAYMENT CONFIRMATION block first.",
  "Never call Confirm Payment until the target order is resolved.",
  "If a mutation tool returns no matching row, explain that the order could not be updated and ask for a clearer reference or the current status. Do not append invisible tags.",
  "After Confirm Order succeeds, append [ORDER_CONFIRMED: <order_number> | <customer_chat_id>] at the very end.",
  "After Confirm Payment succeeds, append [PAYMENT_CONFIRMED: <order_number> | <customer_chat_id>] at the very end.",
  "Never append invisible tags on clarification turns.",
  "If the confirmed order has delivery_type = delivery, ask exactly once: Do you want me to arrange delivery now?",
  "Do not arrange delivery automatically after payment.",
  hasServiceComponent ? "For service bookings, delivered means completed." : "",
  typicalDuration ? "Typical duration: " + typicalDuration : "",
  depositPolicy ? "Deposit policy: " + depositPolicy : "",
  cancellationPolicy ? "Cancellation policy: " + cancellationPolicy : ""
].filter(Boolean).join("\n");

const dispatchRules = hasProductComponent ? [
  "Mark as dispatched or update table_29 to dispatched means Update Order Status Tool only.",
  "Dispatch this order, arrange delivery, or send via courier means Terminal Africa tools.",
  "Never create dispatch automatically just because payment was confirmed.",
  "Start from table_30 order details and loaded business context first.",
  "Ask only for missing dispatch fields.",
  "Ask for missing dispatch fields once, in one concise message.",
  "Do not repeat the same dispatch request in the same reply.",
  "Flow: get quotes, owner picks rate, ask payment_method, confirm dispatch, and let the dispatch workflow persist the shipment and mark the linked customer order as dispatched.",
  "If shipment_id is already known, use Terminal_Track Dispatch.",
  "If shipment_id is not known, use Context Resolver with dispatch lookup first.",
  "If dispatch lookup is ambiguous, ask one short clarification.",
  "Treat loaded order data as the first source of truth for recipient, item, and delivery details.",
  "Do not ask for recipient or order details that already exist in the active order context."
].join("\n") : "";

const imageRules = [
  "Save or replace a product image only when the current message includes an image and the product name is known.",
  "If product name is missing, ask once.",
  "If no image was sent in the current message, ask for the photo.",
  "When generating from table_31 saved product photo, call Context Resolver with scope products first and use the returned minio_url.",
  "Never invent or guess an image URL."
].join("\n");

const mediaRules = [
  "Ask for one short confirmation before generating media if user request is unclear.",
  "After the owner agrees, output a short visible line, then [BUFFER: Gimme a sec...], then [FAL_MEDIA_REQUEST: {...}] in the same response.",
  "The FAL_MEDIA_REQUEST JSON must contain EXACTLY these fields:",
  "  generation_mode (required): text_to_image | image_to_image | text_to_video | image_to_video",
  "  input (required): object with generation parameters",
  "  input.prompt (required): the generation prompt string",
  "  input.image_size: 'square_hd' — always include for image modes",
  "  input.image_urls: array with one URL — only for image_to_image",
  "  input.start_image_url: string URL — only for image_to_video",
  "EXAMPLE: [FAL_MEDIA_REQUEST: {\"generation_mode\": \"text_to_image\", \"input\": {\"prompt\": \"a cute cat\", \"image_size\": \"square_hd\"}}]",
  "Never omit generation_mode. Never put prompt outside of input. Never add an endpoint field.",
  "If a saved product image is needed, resolve it first with Context Resolver."
].join("\n");

const customerProfileRules = [
  "Use List Customers to read customer notes and recent customer context.",
  "Use Save Customer Note to write or replace a customer profile note.",
  "When updating an existing note, read the current note first and then write the full updated note.",
  "Use platform_id from order details or customer lookup when saving customer notes."
].join("\n");

const memoryRules = [
  "Use Save Memory for stable business facts or operating rules.",
  "Use short snake_case keys when saving memory.",
  "Use Delete Memory only after identifying the correct saved key from table_32 business memory."
].join("\n");

const hardRules = [
  "Invisible tags are for the outer handler only. Never explain them to the owner.",
  "Only append ORDER_CONFIRMED or PAYMENT_CONFIRMED after the matching tool succeeds.",
  "Do not append tags on clarification turns.",
  "Put invisible tags at the very end of the reply.",
  "Never invent order numbers, customer chat IDs, shipment IDs, URLs, bank details, or balances.",
  "If you are unsure which record the owner means, ask a short clarification instead of guessing."
].join("\n");

const promptSections = [
  "You are " + agentName + ", the owner-facing agent for " + businessName + ". Be warm, direct, concise, and useful.",
  section("OWNER CONTEXT", ownerContext, sep),
  section("LANGUAGE & STYLE", languageRules, sep),
  section("RESPONSE HYGIENE", responseHygiene, sep),
  section("CLARIFICATION STYLE", clarificationStyle, sep),
  section("ACTIVE ORDERS & BOOKINGS", activeOrdersText, sep),
  section("ORDERS AWAITING ORDER CONFIRMATION", confirmCandidatesText, sep),
  section("ORDERS AWAITING PAYMENT CONFIRMATION", paymentCandidatesText, sep),
  section("TOOL ROUTING", routingRules, sep),
  section("ORDER RULES", orderRules, sep),
  dispatchRules ? section("DISPATCH RULES", dispatchRules, sep) : "",
  section("PRODUCT IMAGE RULES", imageRules, sep),
  section("MEDIA RULES", mediaRules, sep),
  section("CUSTOMER PROFILE RULES", customerProfileRules, sep),
  section("BUSINESS MEMORY RULES", memoryRules, sep),
